const payload = $input.first().json;
const event = payload.event;
const data = payload.data;

const emoji = {
  'episode.status_changed': '🔄',
  'episode.published': '🎙️',
  'episode.scheduled': '📅',
  'deliverable.submitted': '📦',
  'deliverable.approved': '✅',
  'deliverable.revision_requested': '✏️',
};

const label = {
  'episode.status_changed': `Episode status changed to *${data.new_status}*`,
  'episode.published': 'Episode published',
  'episode.scheduled': `Episode scheduled for ${data.scheduled_at}`,
  'deliverable.submitted': `Deliverable submitted (${data.type})`,
  'deliverable.approved': 'Deliverable approved',
  'deliverable.revision_requested': 'Revision requested',
};

const icon = emoji[event] || '📣';
const description = label[event] || event;
const title = data.title || 'Untitled';

let text = `${icon} *${description}*\n>*${title}*`;

if (data.reviewer_notes) {
  text += `\n>_${data.reviewer_notes}_`;
}

if (data.share_url) {
  text += `\n><${data.share_url}|Listen now>`;
}

return [{ json: { text } }];
